## Phase 2: Workflow Engine Core (DAG Walker)

### Overview
Build the DAG execution engine — the `walkDag()` function that traverses nodes, executes them, follows edges by port, and pauses/resumes at async nodes. Start with `property-match` as the only condition node and `create-task` as the only action node. Includes template interpolation and visited-set cycle guard.

### Changes Required:

#### 2.1 Template Interpolation

**File**: `src/workflows/template.ts` (new)
**Changes**: Mustache-style `{{path.to.value}}` interpolation

```typescript
/**
 * Replace {{path.to.value}} tokens in a template string
 * with values from the context object.
 */
export function interpolate(template: string, ctx: Record<string, unknown>): string {
  return template.replace(/\{\{([^}]+)\}\}/g, (_match, path: string) => {
    const keys = path.trim().split(".");
    let value: unknown = ctx;
    for (const key of keys) {
      if (value == null || typeof value !== "object") return "";
      value = (value as Record<string, unknown>)[key];
    }
    if (value == null) return "";
    return typeof value === "object" ? JSON.stringify(value) : String(value);
  });
}
```

#### 2.2 Property Match Node

**File**: `src/workflows/nodes/property-match.ts` (new)
**Changes**: Evaluate conditions array against workflow context

```typescript
import type { NodeResult } from "../engine";

export interface PropertyMatchCondition {
  field: string;         // dot-path into context, e.g. "trigger.source"
  op: "eq" | "neq" | "contains" | "not_contains" | "gt" | "lt" | "exists";
  value?: unknown;
}

export interface PropertyMatchConfig {
  conditions: PropertyMatchCondition[];
  mode?: "all" | "any";  // default: "all"
}

export function executePropertyMatch(
  config: PropertyMatchConfig,
  ctx: Record<string, unknown>
): NodeResult {
  const mode = config.mode ?? "all";
  const results = config.conditions.map((cond) => evaluateCondition(cond, ctx));
  const passed = mode === "all" ? results.every(Boolean) : results.some(Boolean);
  return { mode: "instant", nextPort: passed ? "true" : "false", output: { passed, results } };
}

function evaluateCondition(cond: PropertyMatchCondition, ctx: Record<string, unknown>): boolean {
  const value = resolvePath(ctx, cond.field);
  switch (cond.op) {
    case "eq": return value === cond.value;
    case "neq": return value !== cond.value;
    case "contains": return Array.isArray(value) ? value.includes(cond.value) : String(value ?? "").includes(String(cond.value));
    case "not_contains": return Array.isArray(value) ? !value.includes(cond.value) : !String(value ?? "").includes(String(cond.value));
    case "gt": return Number(value) > Number(cond.value);
    case "lt": return Number(value) < Number(cond.value);
    case "exists": return value != null;
    default: return false;
  }
}

function resolvePath(obj: Record<string, unknown>, path: string): unknown {
  const keys = path.split(".");
  let current: unknown = obj;
  for (const key of keys) {
    if (current == null || typeof current !== "object") return undefined;
    current = (current as Record<string, unknown>)[key];
  }
  return current;
}
```

