  1→import { afterAll, beforeAll, describe, expect, test } from "bun:test";
  2→import { unlink } from "node:fs/promises";
  3→import {
  4→  createServer as createHttpServer,
  5→  type IncomingMessage,
  6→  type Server,
  7→  type ServerResponse,
  8→} from "node:http";
  9→import { closeDb, getAllTasks, initDb } from "../be/db";
 10→import { getPathSegments, parseQueryParams } from "../http/utils";
 11→import { handleWorkflows } from "../http/workflows";
 12→import { workflowEventBus } from "../workflows/event-bus";
 13→import { setupWorkflowResumeListener } from "../workflows/resume";
 14→import { evaluateWorkflowTriggers } from "../workflows/triggers";
 15→
 16→const TEST_DB_PATH = "./test-workflow-http.sqlite";
 17→const TEST_PORT = 13026;
 18→
 19→function createTestServer(): Server {
 20→  return createHttpServer(async (req: IncomingMessage, res: ServerResponse) => {
 21→    res.setHeader("Content-Type", "application/json");
 22→    const pathSegments = getPathSegments(req.url || "");
 23→    const queryParams = parseQueryParams(req.url || "");
 24→    // Pass a stub agent id so auth checks treat caller as an agent
 25→    const myAgentId = req.headers["x-agent-id"] as string | undefined;
 26→
 27→    const handled = await handleWorkflows(req, res, pathSegments, queryParams, myAgentId);
 28→    if (!handled) {
 29→      res.writeHead(404);
 30→      res.end(JSON.stringify({ error: "Not found" }));
 31→    }
 32→  });
 33→}
 34→
 35→describe("Workflow HTTP API", () => {
 36→  let server: Server;
 37→  const baseUrl = `http://localhost:${TEST_PORT}`;
 38→
 39→  beforeAll(async () => {
 40→    try {
 41→      await unlink(TEST_DB_PATH);
 42→    } catch {
 43→      // File doesn't exist, that's fine
 44→    }
 45→    initDb(TEST_DB_PATH);
 46→    setupWorkflowResumeListener(workflowEventBus);
 47→
 48→    server = createTestServer();
 49→    await new Promise<void>((resolve) => {
 50→      server.listen(TEST_PORT, () => {
 51→        console.log(`Test server listening on port ${TEST_PORT}`);
 52→        resolve();
 53→      });
 54→    });
 55→  });
 56→
 57→  afterAll(async () => {
 58→    await new Promise<void>((resolve) => server.close(() => resolve()));
 59→    closeDb();
 60→    for (const suffix of ["", "-wal", "-shm"]) {
 61→      try {
 62→        await unlink(`${TEST_DB_PATH}${suffix}`);
 63→      } catch {
 64→        // File may not exist
 65→      }
 66→    }
 67→  });
 68→
 69→  // ---------------------------------------------------------------------------
 70→  // POST /api/workflows — create
 71→  // GET /api/workflows — list
 72→  // GET /api/workflows/:id — get single
 73→  // ---------------------------------------------------------------------------
 74→  describe("CRUD", () => {
 75→    let workflowId: string;
 76→
 77→    test("POST /api/workflows creates a workflow", async () => {
 78→      const res = await fetch(`${baseUrl}/api/workflows`, {
 79→        method: "POST",
 80→        headers: { "Content-Type": "application/json", "X-Agent-ID": "agent-1" },
 81→        body: JSON.stringify({
 82→          name: "test-crud-workflow",
 83→          definition: {
 84→            nodes: [
 85→              { id: "t1", type: "trigger-webhook", config: {} },
 86→              { id: "a1", type: "create-task", config: { template: "Task from workflow" } },
 87→            ],
 88→            edges: [{ id: "e1", source: "t1", sourcePort: "default", target: "a1" }],
 89→          },
 90→        }),
 91→      });
 92→      expect(res.status).toBe(201);
 93→      const body = (await res.json()) as { id: string; name: string; enabled: boolean };
 94→      expect(body.name).toBe("test-crud-workflow");
 95→      expect(body.enabled).toBe(true);
 96→      expect(typeof body.id).toBe("string");
 97→      workflowId = body.id;
 98→    });
 99→
100→    test("GET /api/workflows lists workflows", async () => {
101→      const res = await fetch(`${baseUrl}/api/workflows`, {
102→        headers: { "X-Agent-ID": "agent-1" },
103→      });
104→      expect(res.status).toBe(200);
105→      const body = (await res.json()) as Array<{ id: string }>;
106→      expect(Array.isArray(body)).toBe(true);
107→      expect(body.some((w) => w.id === workflowId)).toBe(true);
108→    });
109→
110→    test("GET /api/workflows/:id returns the workflow", async () => {
111→      const res = await fetch(`${baseUrl}/api/workflows/${workflowId}`, {
112→        headers: { "X-Agent-ID": "agent-1" },
113→      });
114→      expect(res.status).toBe(200);
115→      const body = (await res.json()) as { id: string; name: string };
116→      expect(body.id).toBe(workflowId);
117→      expect(body.name).toBe("test-crud-workflow");
118→    });
119→
120→    test("GET /api/workflows/:id returns 404 for unknown id", async () => {
121→      const res = await fetch(`${baseUrl}/api/workflows/does-not-exist`, {
122→        headers: { "X-Agent-ID": "agent-1" },
123→      });
124→      expect(res.status).toBe(404);
125→    });
126→
127→    test("PUT /api/workflows/:id updates the workflow", async () => {
128→      const res = await fetch(`${baseUrl}/api/workflows/${workflowId}`, {
129→        method: "PUT",
130→        headers: { "Content-Type": "application/json", "X-Agent-ID": "agent-1" },
131→        body: JSON.stringify({ name: "test-crud-workflow-updated" }),
132→      });
133→      expect(res.status).toBe(200);
134→      const body = (await res.json()) as { name: string };
135→      expect(body.name).toBe("test-crud-workflow-updated");
136→    });
137→  });
138→
139→  // ---------------------------------------------------------------------------
140→  // POST /api/workflows/:id/trigger — webhook trigger creates a run
141→  // GET /api/workflows/:id/runs — lists runs
142→  // GET /api/workflow-runs/:id — run detail with steps
143→  // ---------------------------------------------------------------------------
144→  describe("Trigger and run detail", () => {
145→    let workflowId: string;
146→    let runId: string;
147→
148→    test("setup: create workflow for trigger tests", async () => {
149→      const res = await fetch(`${baseUrl}/api/workflows`, {
150→        method: "POST",
151→        headers: { "Content-Type": "application/json", "X-Agent-ID": "agent-1" },
152→        body: JSON.stringify({
153→          name: "test-trigger-workflow",
154→          definition: {
155→            nodes: [
156→              { id: "t1", type: "trigger-webhook", config: {} },
157→              { id: "a1", type: "create-task", config: { template: "Triggered task" } },
158→            ],
159→            edges: [{ id: "e1", source: "t1", sourcePort: "default", target: "a1" }],
160→          },
161→        }),
162→      });
163→      expect(res.status).toBe(201);
164→      const body = (await res.json()) as { id: string };
165→      workflowId = body.id;
166→    });
167→
168→    test("POST /api/workflows/:id/trigger creates a workflow run", async () => {
169→      const res = await fetch(`${baseUrl}/api/workflows/${workflowId}/trigger`, {
170→        method: "POST",
171→        headers: { "Content-Type": "application/json", "X-Agent-ID": "agent-1" },
172→        body: JSON.stringify({ data: "test-payload" }),
173→      });
174→      expect(res.status).toBe(201);
175→      const body = (await res.json()) as { runId: string };
176→      expect(typeof body.runId).toBe("string");
177→      runId = body.runId;
178→    });
179→
180→    test("GET /api/workflows/:id/runs lists the run", async () => {
181→      const res = await fetch(`${baseUrl}/api/workflows/${workflowId}/runs`, {
182→        headers: { "X-Agent-ID": "agent-1" },
183→      });
184→      expect(res.status).toBe(200);
185→      const body = (await res.json()) as Array<{ id: string }>;
186→      expect(Array.isArray(body)).toBe(true);
187→      expect(body.some((r) => r.id === runId)).toBe(true);
188→    });
189→
190→    test("GET /api/workflow-runs/:id returns run with steps", async () => {
191→      const res = await fetch(`${baseUrl}/api/workflow-runs/${runId}`, {
192→        headers: { "X-Agent-ID": "agent-1" },
193→      });
194→      expect(res.status).toBe(200);
195→      const body = (await res.json()) as { id: string; steps: Array<{ nodeId: string }> };
196→      expect(body.id).toBe(runId);
197→      expect(Array.isArray(body.steps)).toBe(true);
198→      // t1 (trigger-webhook) and a1 (create-task) should both appear
199→      const nodeIds = body.steps.map((s) => s.nodeId);
200→      expect(nodeIds).toContain("t1");
201→      expect(nodeIds).toContain("a1");
202→    });
