205→  // ---------------------------------------------------------------------------
206→  // Trigger subscription: trigger-new-task with matchTags fires on task.created
207→  // ---------------------------------------------------------------------------
208→  describe("Trigger subscription: trigger-new-task with matchTags", () => {
209→    test("workflow fires when task.created event matches tag filter", async () => {
210→      // Create a workflow: trigger-new-task (matchTags: ["test"]) → create-task
211→      const res = await fetch(`${baseUrl}/api/workflows`, {
212→        method: "POST",
213→        headers: { "Content-Type": "application/json", "X-Agent-ID": "agent-1" },
214→        body: JSON.stringify({
215→          name: "test-tag-trigger-workflow",
216→          definition: {
217→            nodes: [
218→              {
219→                id: "t1",
220→                type: "trigger-new-task",
221→                config: { matchTags: ["test"] },
222→              },
223→              {
224→                id: "a1",
225→                type: "create-task",
226→                config: { template: "Downstream task from trigger" },
227→              },
228→            ],
229→            edges: [{ id: "e1", source: "t1", sourcePort: "default", target: "a1" }],
230→          },
231→        }),
232→      });
233→      expect(res.status).toBe(201);
234→
235→      // Snapshot existing task IDs before triggering
236→      const idsBefore = new Set(getAllTasks().map((t) => t.id));
237→
238→      // Emit a task.created event that matches the tag filter (no workflowRunId to avoid loop guard)
239→      evaluateWorkflowTriggers("task.created", {
240→        tags: ["test", "other"],
241→        source: "api",
242→      });
243→
244→      // Give async execution a moment
245→      await new Promise((resolve) => setTimeout(resolve, 100));
246→
247→      // A downstream task matching our specific template should have been created
248→      const newTasks = getAllTasks().filter((t) => !idsBefore.has(t.id));
249→      const workflowTask = newTasks.find(
250→        (t) => t.source === "workflow" && t.task === "Downstream task from trigger",
251→      );
252→      expect(workflowTask).toBeDefined();
253→      expect(workflowTask?.task).toBe("Downstream task from trigger");
254→    });
255→
256→    test("workflow does NOT fire when tags do not match", async () => {
257→      const idsBefore = new Set(getAllTasks().map((t) => t.id));
