export interface AgentMailInboxMapping {
  id: string;
  inboxId: string;
  agentId: string;
  inboxEmail: string | null;
  createdAt: string;
}

export function getAgentMailInboxMapping(inboxId: string): AgentMailInboxMapping | null {
