    getDb()
      .prepare<AgentMailInboxMapping, [string]>(
        "SELECT * FROM agentmail_inbox_mappings WHERE inboxId = ?",
      )
      .get(inboxId) ?? null
  );
}

export function getAgentMailInboxMappingsByAgent(agentId: string): AgentMailInboxMapping[] {
