    params.push(opts.agentId);
  }
  if (opts.startDate) {
    conditions.push("createdAt >= ?");
    params.push(opts.startDate);
  }
  if (opts.endDate) {
    conditions.push("createdAt <= ?");
    params.push(opts.endDate);
  }

  const where = conditions.length > 0 ? `WHERE ${conditions.join(" AND ")}` : "";
  const limit = opts.limit ?? 100;
