  1→import { listWorkflows } from "../be/db";
  2→import type { WorkflowNode } from "../types";
  3→import { findEntryNodes, startWorkflowExecution } from "./engine";
  4→
  5→export function evaluateWorkflowTriggers(eventType: string, eventData: unknown): void {
  6→  const workflows = listWorkflows({ enabled: true });
  7→  for (const workflow of workflows) {
  8→    const entryNodes = findEntryNodes(workflow.definition);
  9→    for (const node of entryNodes) {
 10→      if (matchTriggerNode(node, eventType, eventData)) {
 11→        startWorkflowExecution(workflow, eventData).catch((err) => {
 12→          console.error(`[workflows] Failed to start workflow ${workflow.name}:`, err);
 13→        });
 14→      }
 15→    }
 16→  }
 17→}
 18→
 19→function matchTriggerNode(node: WorkflowNode, eventType: string, eventData: unknown): boolean {
 20→  const data = eventData as Record<string, unknown>;
 21→
 22→  switch (node.type) {
 23→    case "trigger-new-task":
 24→      if (eventType !== "task.created") return false;
 25→      // Don't trigger on tasks created by workflows (prevent infinite loops)
 26→      if (data.workflowRunId) return false;
 27→      return matchTaskFilters(node.config as Record<string, unknown>, data);
 28→
 29→    case "trigger-task-completed":
 30→      if (eventType !== "task.completed") return false;
 31→      return matchTaskFilters(node.config as Record<string, unknown>, data);
 32→
 33→    case "trigger-github-event":
 34→      if (!eventType.startsWith("github.")) return false;
 35→      return matchEventFilters(node.config as Record<string, unknown>, eventType, data);
 36→
 37→    case "trigger-slack-message":
 38→      if (eventType !== "slack.message") return false;
 39→      return matchSlackFilters(node.config as Record<string, unknown>, data);
 40→
 41→    case "trigger-email":
 42→      if (eventType !== "agentmail.message.received") return false;
 43→      return matchEmailFilters(node.config as Record<string, unknown>, data);
 44→
 45→    case "trigger-webhook":
 46→      return false; // Webhooks are triggered via HTTP, not event bus
 47→
 48→    default:
 49→      return false;
 50→  }
 51→}
 52→
 53→function matchTaskFilters(config: Record<string, unknown>, data: Record<string, unknown>): boolean {
 54→  if (config.matchTags && Array.isArray(config.matchTags)) {
 55→    const taskTags = (data.tags as string[]) ?? [];
 56→    if (!config.matchTags.every((t: string) => taskTags.includes(t))) return false;
 57→  }
 58→  if (config.matchSource && data.source !== config.matchSource) return false;
 59→  if (config.matchTaskType && data.taskType !== config.matchTaskType) return false;
 60→  if (config.matchAgentId && data.agentId !== config.matchAgentId) return false;
 61→  return true;
 62→}
 63→
 64→function matchEventFilters(
 65→  config: Record<string, unknown>,
 66→  eventType: string,
 67→  data: Record<string, unknown>,
 68→): boolean {
 69→  if (config.matchEventType) {
 70→    const expectedEvent = `github.${config.matchEventType}`;
 71→    if (eventType !== expectedEvent) return false;
 72→  }
 73→  if (config.matchRepo && data.repo !== config.matchRepo) return false;
 74→  return true;
 75→}
 76→
 77→function matchSlackFilters(
 78→  config: Record<string, unknown>,
 79→  data: Record<string, unknown>,
 80→): boolean {
 81→  if (config.matchChannel && data.channel !== config.matchChannel) return false;
 82→  if (config.matchPattern) {
 83→    const text = String(data.text ?? "");
 84→    if (!new RegExp(config.matchPattern as string, "i").test(text)) return false;
 85→  }
 86→  return true;
 87→}
 88→
 89→function matchEmailFilters(
 90→  config: Record<string, unknown>,
 91→  data: Record<string, unknown>,
 92→): boolean {
 93→  if (config.matchInbox && data.inboxId !== config.matchInbox) return false;
 94→  if (config.matchSenderDomain) {
 95→    const from = String(data.from ?? "");
 96→    if (!from.endsWith(`@${config.matchSenderDomain}`)) return false;
 97→  }
