  1→#!/usr/bin/env bun
  2→/**
  3→ * E2E Workflow Engine Test
  4→ *
  5→ * Spins up the full API server with a clean DB, optionally builds & runs
  6→ * Docker lead+worker containers, then exercises the workflow REST API:
  7→ *   - CRUD lifecycle
  8→ *   - Trigger with property-match routing (pass + reject)
  9→ *   - Code-match node execution
 10→ *   - Disabled workflow rejection
 11→ *   - Webhook secret auth
 12→ *   - Failed-run retry
 13→ *   - Delete
 14→ *
 15→ * Usage:
 16→ *   bun scripts/e2e-workflow-test.ts                  # API-only (no docker)
 17→ *   bun scripts/e2e-workflow-test.ts --with-docker    # Also build+spawn docker lead/worker
 18→ *   E2E_PORT=13099 bun scripts/e2e-workflow-test.ts   # Custom port
 19→ */
 20→import { type Subprocess, $ } from "bun";
 21→
 22→// ─── Config ─────────────────────────────────────────────────────────────────
 23→const PORT = process.env.E2E_PORT || "13099";
 24→const API_KEY = process.env.API_KEY || "123123";
 25→const BASE_URL = `http://localhost:${PORT}`;
 26→const DB_PATH = `/tmp/e2e-workflow-${Date.now()}.sqlite`;
 27→const AGENT_ID = crypto.randomUUID();
 28→const WITH_DOCKER = process.argv.includes("--with-docker");
 29→const DOCKER_IMAGE = "agent-swarm-worker:e2e";
 30→const LEAD_CONTAINER = `e2e-lead-${Date.now()}`;
 31→const WORKER_CONTAINER = `e2e-worker-${Date.now()}`;
 32→const LEAD_PORT = Number(PORT) + 101; // e.g. 13200
 33→const WORKER_PORT = Number(PORT) + 102; // e.g. 13201
 34→
 35→// ─── State ──────────────────────────────────────────────────────────────────
 36→let apiProc: Subprocess | null = null;
 37→const dockerContainers: string[] = [];
 38→let pass = 0;
 39→let fail = 0;
 40→let cleaningUp = false;
 41→
 42→// ─── Helpers ────────────────────────────────────────────────────────────────
 43→function log(msg: string) {
 44→  console.log(`\x1b[1;34m[E2E]\x1b[0m ${msg}`);
 45→}
 46→function logPass(name: string) {
 47→  console.log(`\x1b[1;32m  PASS\x1b[0m ${name}`);
 48→  pass++;
 49→}
 50→function logFail(name: string, detail: string) {
 51→  console.log(`\x1b[1;31m  FAIL\x1b[0m ${name}: ${detail}`);
 52→  fail++;
 53→}
 54→
 55→function assert(condition: boolean, name: string, detail = "") {
 56→  if (condition) logPass(name);
 57→  else logFail(name, detail || "assertion failed");
 58→}
 59→
 60→function assertEq(actual: unknown, expected: unknown, name: string) {
 61→  if (actual === expected) logPass(name);
 62→  else logFail(name, `expected '${expected}', got '${actual}'`);
 63→}
 64→
 65→async function api<T = unknown>(
 66→  method: string,
 67→  path: string,
 68→  body?: unknown,
 69→): Promise<{ status: number; data: T }> {
 70→  const opts: RequestInit = {
 71→    method,
 72→    headers: {
 73→      "Content-Type": "application/json",
 74→      Authorization: `Bearer ${API_KEY}`,
 75→      "X-Agent-ID": AGENT_ID,
 76→    },
 77→  };
 78→  if (body !== undefined) opts.body = JSON.stringify(body);
 79→  const res = await fetch(`${BASE_URL}${path}`, opts);
 80→  let data: T;
 81→  try {
 82→    data = (await res.json()) as T;
 83→  } catch {
 84→    data = null as T;
 85→  }
 86→  return { status: res.status, data };
 87→}
 88→
 89→/** fetch without X-Agent-ID header (for auth tests) */
 90→async function fetchNoAgent(
 91→  method: string,
 92→  path: string,
 93→  body?: unknown,
 94→): Promise<{ status: number }> {
 95→  const opts: RequestInit = {
 96→    method,
 97→    headers: {
 98→      "Content-Type": "application/json",
 99→      Authorization: `Bearer ${API_KEY}`,
100→    },
101→  };
102→  if (body !== undefined) opts.body = JSON.stringify(body);
103→  const res = await fetch(`${BASE_URL}${path}`, opts);
104→  try {
105→    await res.text();
106→  } catch {
107→    /* drain */
108→  }
109→  return { status: res.status };
110→}
111→
112→async function waitForServer(url: string, timeoutMs = 30_000): Promise<void> {
113→  const start = Date.now();
114→  while (Date.now() - start < timeoutMs) {
115→    try {
116→      const res = await fetch(`${url}/api/agents`, {
117→        headers: { Authorization: `Bearer ${API_KEY}` },
118→      });
119→      if (res.ok) return;
120→    } catch {
121→      // not ready yet
122→    }
123→    await Bun.sleep(500);
124→  }
125→  throw new Error(`Server at ${url} did not start within ${timeoutMs}ms`);
126→}
127→
128→// ─── Cleanup ────────────────────────────────────────────────────────────────
129→async function cleanup() {
130→  if (cleaningUp) return;
131→  cleaningUp = true;
132→  log("Cleaning up...");
133→
134→  // Stop docker containers
135→  for (const name of dockerContainers) {
136→    try {
137→      await $`docker stop ${name}`.quiet();
138→      log(`Stopped container ${name}`);
139→    } catch {
140→      // already stopped
141→    }
142→    try {
143→      await $`docker rm -f ${name}`.quiet();
144→    } catch {
145→      // already removed
146→    }
147→  }
148→
149→  // Kill API process
150→  if (apiProc) {
151→    try {
152→      apiProc.kill("SIGTERM");
153→      // Give it a moment to shut down gracefully
154→      await Bun.sleep(1000);
155→      if (apiProc.exitCode === null) apiProc.kill("SIGKILL");
156→    } catch {
157→      // already dead
158→    }
159→    apiProc = null;
160→  }
161→
162→  // Remove temp DB files
163→  for (const suffix of ["", "-wal", "-shm"]) {
164→    try {
165→      await $`rm -f ${DB_PATH}${suffix}`.quiet();
166→    } catch {
167→      // fine
168→    }
169→  }
170→
171→  log("Cleanup complete.");
172→}
173→
174→process.on("SIGINT", async () => {
175→  await cleanup();
176→  process.exit(fail > 0 ? 1 : 0);
177→});
178→process.on("SIGTERM", async () => {
179→  await cleanup();
180→  process.exit(fail > 0 ? 1 : 0);
181→});
182→
183→// ─── Step 0: Start API server ───────────────────────────────────────────────
184→async function startApi() {
185→  log(`Starting API server on port ${PORT} with DB at ${DB_PATH}...`);
186→  apiProc = Bun.spawn(["bun", "src/http.ts"], {
187→    cwd: import.meta.dir + "/..",
188→    env: {
189→      ...process.env,
190→      PORT,
191→      API_KEY,
192→      DATABASE_PATH: DB_PATH,
193→      SLACK_DISABLE: "true",
194→      GITHUB_DISABLE: "true",
195→      HEARTBEAT_DISABLE: "true",
196→      // Prevent agentmail init from failing
197→      AGENTMAIL_DISABLE: "true",
198→    },
199→    stdout: "pipe",
200→    stderr: "pipe",
201→  });
202→
203→  // Stream API logs in background (prefix with [API])
204→  const decoder = new TextDecoder();
205→  const pipeOutput = async (stream: ReadableStream<Uint8Array>, prefix: string) => {
206→    const reader = stream.getReader();
207→    let buffer = "";
208→    try {
209→      while (true) {
210→        const { done, value } = await reader.read();
211→        if (done) break;
212→        buffer += decoder.decode(value, { stream: true });
213→        const lines = buffer.split("\n");
214→        buffer = lines.pop() || "";
215→        for (const line of lines) {
216→          if (line.trim()) console.log(`  \x1b[90m${prefix}\x1b[0m ${line}`);
217→        }
218→      }
219→    } catch {
220→      // stream closed
221→    }
222→  };
223→  pipeOutput(apiProc.stdout, "[API]");
224→  pipeOutput(apiProc.stderr, "[API]");
225→
226→  await waitForServer(BASE_URL);
227→  log("API server is up.");
228→}
229→
230→// ─── Step 1: Build Docker ───────────────────────────────────────────────────
231→async function buildDocker() {
232→  log("Building Docker worker image...");
233→  const projectRoot = import.meta.dir + "/..";
234→  await $`docker build -f Dockerfile.worker -t ${DOCKER_IMAGE} ${projectRoot}`;
235→  log("Docker image built.");
236→}
237→
238→// ─── Step 2: Spawn lead + worker containers ─────────────────────────────────
239→async function spawnContainers() {
240→  const projectRoot = import.meta.dir + "/..";
241→  const envDockerPath = `${projectRoot}/.env.docker`;
242→
243→  // Lead
244→  log(`Spawning lead container (${LEAD_CONTAINER}) on port ${LEAD_PORT}...`);
245→  await $`docker run --rm -d \
246→    --name ${LEAD_CONTAINER} \
247→    --env-file ${envDockerPath} \
248→    -e MCP_BASE_URL=http://host.docker.internal:${PORT} \
249→    -e AGENT_ROLE=lead \
250→    -e MAX_CONCURRENT_TASKS=1 \
251→    -p ${String(LEAD_PORT)}:3000 \
252→    ${DOCKER_IMAGE}`.quiet();
253→  dockerContainers.push(LEAD_CONTAINER);
254→  log("Lead container started.");
255→
256→  // Worker
257→  log(`Spawning worker container (${WORKER_CONTAINER}) on port ${WORKER_PORT}...`);
258→  await $`docker run --rm -d \
259→    --name ${WORKER_CONTAINER} \
260→    --env-file ${envDockerPath} \
261→    -e MCP_BASE_URL=http://host.docker.internal:${PORT} \
262→    -e AGENT_ROLE=worker \
263→    -e MAX_CONCURRENT_TASKS=1 \
264→    -p ${String(WORKER_PORT)}:3000 \
265→    ${DOCKER_IMAGE}`.quiet();
266→  dockerContainers.push(WORKER_CONTAINER);
267→  log("Worker container started.");
268→
269→  // Wait a few seconds for containers to register with the API
270→  log("Waiting for containers to register...");
271→  await Bun.sleep(5000);
272→
273→  // Verify containers are running
274→  const leadRunning =
275→    (await $`docker inspect -f '{{.State.Running}}' ${LEAD_CONTAINER}`.quiet().text()).trim() ===
276→    "true";
277→  const workerRunning =
278→    (await $`docker inspect -f '{{.State.Running}}' ${WORKER_CONTAINER}`.quiet().text()).trim() ===
279→    "true";
280→  assert(leadRunning, "Lead container is running");
281→  assert(workerRunning, "Worker container is running");
282→}
283→
284→// ─── Workflow Definitions (configurable) ────────────────────────────────────
285→interface WorkflowScenario {
286→  name: string;
287→  definition: {
288→    nodes: Array<{ id: string; type: string; config: Record<string, unknown> }>;
289→    edges: Array<{ id: string; source: string; sourcePort: string; target: string }>;
290→  };
291→}
292→
293→const SCENARIOS: Record<string, WorkflowScenario> = {
294→  /** trigger-webhook → property-match (priority > 5) → create-task */
295→  triagePriority: {
296→    name: "e2e-triage-priority",
297→    definition: {
298→      nodes: [
299→        { id: "t1", type: "trigger-webhook", config: {} },
300→        {
301→          id: "pm1",
302→          type: "property-match",
303→          config: {
304→            conditions: [{ field: "trigger.priority", op: "gt", value: 5 }],
305→          },
306→        },
307→        {
308→          id: "ct1",
309→          type: "create-task",
310→          config: { template: "High priority: {{trigger.title}}" },
311→        },
312→      ],
313→      edges: [
314→        { id: "e1", source: "t1", sourcePort: "default", target: "pm1" },
315→        { id: "e2", source: "pm1", sourcePort: "true", target: "ct1" },
316→      ],
317→    },
318→  },
319→
320→  /** trigger-webhook → code-match (checks tags) → create-task */
321→  codeMatchTags: {
322→    name: "e2e-code-match-tags",
323→    definition: {
324→      nodes: [
325→        { id: "t1", type: "trigger-webhook", config: {} },
326→        {
327→          id: "cm1",
328→          type: "code-match",
329→          config: {
330→            code: "(input) => input.trigger.tags && input.trigger.tags.includes('urgent')",
331→            outputPorts: ["true", "false"],
332→          },
333→        },
334→        {
335→          id: "ct1",
336→          type: "create-task",
337→          config: { template: "Urgent: {{trigger.title}}" },
338→        },
339→      ],
340→      edges: [
341→        { id: "e1", source: "t1", sourcePort: "default", target: "cm1" },
342→        { id: "e2", source: "cm1", sourcePort: "true", target: "ct1" },
343→      ],
344→    },
345→  },
346→
347→  /** trigger-webhook → code-match that throws → should fail */
348→  failingCodeMatch: {
349→    name: "e2e-failing-code-match",
350→    definition: {
351→      nodes: [
352→        { id: "t1", type: "trigger-webhook", config: {} },
353→        {
354→          id: "cm1",
355→          type: "code-match",
356→          config: {
357→            code: '(input) => { throw new Error("intentional failure"); }',
358→            outputPorts: ["true", "false"],
359→          },
360→        },
361→      ],
362→      edges: [{ id: "e1", source: "t1", sourcePort: "default", target: "cm1" }],
363→    },
364→  },
365→
366→  /** trigger-webhook only (minimal, for edge-case tests) */
367→  minimal: {
368→    name: "e2e-minimal",
369→    definition: {
370→      nodes: [{ id: "t1", type: "trigger-webhook", config: {} }],
371→      edges: [],
372→    },
373→  },
374→};
