394→async function testWorkflowCrud() {
395→  log("Test: Workflow CRUD lifecycle");
396→
397→  // Create
398→  const { status: createStatus, data: wf } = await api<WfJson>("POST", "/api/workflows", {
399→    name: SCENARIOS.triagePriority.name,
