435→async function testTriggerHighPriority(workflowId: string) {
436→  log("Test: Trigger workflow (high priority → task created)");
437→
438→  const { status, data } = await api<RunJson>("POST", `/api/workflows/${workflowId}/trigger`, {
439→    priority: 8,
