442→  assertEq(status, 201, "Trigger returns 201");
443→  assert(typeof data.runId === "string", "Trigger returns runId");
444→
445→  // Wait for async execution
446→  await Bun.sleep(1000);
447→
448→  const { data: run } = await api<RunDetailJson>("GET", `/api/workflow-runs/${data.runId}`);
449→  assert(Array.isArray(run.steps) && run.steps.length > 0, "Run has steps");
