501→async function testCodeMatch() {
502→  log("Test: Code-match node execution");
503→
504→  // Create code-match workflow
505→  const { data: wf } = await api<WfJson>("POST", "/api/workflows", {
506→    name: SCENARIOS.codeMatchTags.name,
507→    definition: SCENARIOS.codeMatchTags.definition,
