613→// ─── Main ───────────────────────────────────────────────────────────────────
614→async function main() {
615→  log("=== E2E Workflow Engine Test ===");
616→  log(`PORT=${PORT}  DB=${DB_PATH}  DOCKER=${WITH_DOCKER}`);
