await testValidation();
await testDeleteWorkflow(workflowId);

// Step 6: Full worker E2E (only with Docker)
if (WITH_DOCKER) {
  await testWorkerE2EFlow();
} else {
  log("Skipping worker E2E flow test (run with --with-docker to enable)");
}

