        { id: "t1", type: "trigger-webhook", config: {} },
        {
          id: "cm1",
          type: "code-match",
          config: {
            code: "(input) => input.trigger.tags && input.trigger.tags.includes('urgent')",
            outputPorts: ["true", "false"],
          },
